import React from 'react';
import { Card, CardContent, Typography, Stack, Box } from '@mui/material';
import response from './response.json';

interface Headline {
  title: string;
  source: string;
  timeAgo: string;
}

interface NewsData {
  headlines: Headline[];
}

export default function Widget() {
  const newsData = response.data as NewsData;
  const { headlines } = newsData;
  const { theme, primaryColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#1E1E1E',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
            Top News
          </Typography>
          <Stack spacing={1}>
            {headlines.map((headline, index) => (
              <Box key={index}>
                <Typography variant="body1" fontWeight={500} sx={{ color: '#4A4A4A' }}>
                  {headline.title}
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  {headline.source} - {headline.timeAgo}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
